class Solution:
    def findIntegers(self, n):
        from functools import lru_cache
        bits = [int(c) for c in bin(n)[2:]]
        L = len(bits)
        @lru_cache(maxsize=None)
        def dp(i, prev, tight):
            if i == L:
                return 1
            hi = bits[i] if tight else 1
            total = 0
            for d in range(0, hi + 1):
                if d == 1 and prev == 1:
                    continue
                total += dp(i + 1, d, tight and d == hi)
            return total
        return dp(0, 0, True)

