class Solution:
    def findIntegers(self, n):
        fib = [1, 2]
        while len(fib) < 31:
            fib.append(fib[-1] + fib[-2])
        bits = bin(n)[2:]
        L = len(bits)
        result = 0
        prev = 0
        for i, ch in enumerate(bits):
            if ch == '1':
                result += fib[L - 1 - i]
                if prev == 1:
                    return result
                prev = 1
            else:
                prev = 0
        return result + 1

