    while (fib.length < 31) fib.push(fib[fib.length - 1] + fib[fib.length - 2]);
    const bits = n.toString(2);
    const L = bits.length;
    let result = 0;
    let prev = 0;
    for (let i = 0; i < L; i++) {
        if (bits[i] === '1') {
            result += fib[L - 1 - i];
            if (prev === 1) return result;
            prev = 1;
        } else {
            prev = 0;
        }
    }
    return result + 1;
